import{_ as i,o as t,c as e,ag as a}from"./chunks/framework.BZohXCq9.js";const d=JSON.parse('{"title":"[Client / App Specs] Sprint 2: Điểm đến (POI Display)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/02-quan-ly-sprint/sprint-2-quan-tri-diem-den/07-client-app-specs.md","filePath":"99-tham-khao/archive/02-quan-ly-sprint/sprint-2-quan-tri-diem-den/07-client-app-specs.md"}'),o={name:"99-tham-khao/archive/02-quan-ly-sprint/sprint-2-quan-tri-diem-den/07-client-app-specs.md"};function r(l,n,h,c,s,g){return t(),e("div",null,[...n[0]||(n[0]=[a('<h1 id="client-app-specs-sprint-2-điem-đen-poi-display" tabindex="-1">[Client / App Specs] Sprint 2: Điểm đến (POI Display) <a class="header-anchor" href="#client-app-specs-sprint-2-điem-đen-poi-display" aria-label="Permalink to &quot;[Client / App Specs] Sprint 2: Điểm đến (POI Display)&quot;">​</a></h1><p>Đặc tả chi tiết giao diện và hiển thị Điểm đến dành cho Khách hàng tại Web Client và Mobile App.</p><h2 id="_1-man-hinh-trang-chu-homepage" tabindex="-1">1. Màn hình Trang chủ (Homepage) <a class="header-anchor" href="#_1-man-hinh-trang-chu-homepage" aria-label="Permalink to &quot;1. Màn hình Trang chủ (Homepage)&quot;">​</a></h2><ul><li><strong>Web Client</strong>: <ul><li><strong>Section</strong>: &quot;Điểm đến nổi bật&quot;.</li><li><strong>UI</strong>: Carousel/Grid hiển thị Card Điểm đến.</li><li><strong>Card View</strong>: Ảnh bao phủ toàn bộ thẻ (Glassmorphism overlay) với tên Vùng miền ở góc trái và tên Điểm đến ở trung tâm.</li></ul></li><li><strong>Mobile App</strong>: <ul><li><strong>Section</strong>: &quot;Khám phá Vùng miền&quot;.</li><li><strong>UI</strong>: Horizontal Scroll View (3 Regions: Bắc, Trung, Nam).</li><li><strong>Component</strong>: <code>DestCard.tsx</code> (Expo/React Native) với bóng đổ (Shadow) 3D, bo góc tròn 20dp.</li></ul></li></ul><h2 id="_2-trang-danh-muc-điem-đen-destination-directory" tabindex="-1">2. Trang Danh mục Điểm đến (Destination Directory) <a class="header-anchor" href="#_2-trang-danh-muc-điem-đen-destination-directory" aria-label="Permalink to &quot;2. Trang Danh mục Điểm đến (Destination Directory)&quot;">​</a></h2><ul><li><strong>Logic</strong>: Khi click vào một Điểm đến -&gt; Chuyển hướng sang danh sách các Tour tương ứng.</li><li><strong>Web Client</strong>: <code>/[locale]/destinations/[slug]</code></li><li><strong>Mobile App</strong>: <code>(tabs)/discovery/[id]</code></li></ul><h2 id="_3-hien-thi-thong-tin-chi-tiet-detail-view-tuong-lai" tabindex="-1">3. Hiển thị Thông tin Chi tiết (Detail View) - Tương lai <a class="header-anchor" href="#_3-hien-thi-thong-tin-chi-tiet-detail-view-tuong-lai" aria-label="Permalink to &quot;3. Hiển thị Thông tin Chi tiết (Detail View) - Tương lai&quot;">​</a></h2><ul><li>Hiển thị tên (Vi/En), mô tả ngắn, Gallery ảnh (Image Slider/Gallery Zoom).</li><li>Tích hợp bản đồ vị trí (Latitude/Longitude).</li></ul><h2 id="_4-toi-uu-hieu-nang-performance-tuning" tabindex="-1">4. Tối ưu Hiệu năng (Performance Tuning) <a class="header-anchor" href="#_4-toi-uu-hieu-nang-performance-tuning" aria-label="Permalink to &quot;4. Tối ưu Hiệu năng (Performance Tuning)&quot;">​</a></h2><ul><li><strong>Image Optimization</strong>: Sử dụng Cloudinary <code>f_auto,q_auto</code> để tự động chọn định dạng ảnh WebP/AVIF và chất lượng phù hợp với thiết bị.</li><li><strong>Caching</strong>: Dữ liệu danh sách được cache tại Client qua <code>swr</code> hoặc <code>react-query</code> trong vòng 10 phút.</li><li><strong>Lazy Loading</strong>: Các card điểm đến chỉ hiển thị khi user cuộn trang tới (<code>IntersectionObserver</code>).</li></ul><hr><p><em>Tài liệu đặc tả Client/App cho Sprint 2.</em></p>',12)])])}const u=i(o,[["render",r]]);export{d as __pageData,u as default};
